return ($json.image_prompts || []).map((item, i) => ({
  json: {
    prompt: item.prompt,
    prompt_number: i + 1
  }
}));

const results = [];

for (let i = 0; i < items.length; i++) {
  const imageUrl = items[i].json.image;

  if (imageUrl) {
    const obj = {};
    obj["image" + (i + 1)] = imageUrl;

    results.push({
      json: obj
    });
  }
}

return results;

/** @type {{ [key: string]: unknown }} */
const result = {};

for (let i = 0; i < items.length; i++) {
  const data = items[i].json;

  // 1. Post text
  if (data.output && data.output.postText) {
    result.postText = data.output.postText;
  }

  // 2. Template public URL -> template_url
  if (
    data.selected_template &&
    data.selected_template.public_url
  ) {
    result.template_url = data.selected_template.public_url;
  }

  // 3. Image prompts (array, keep as-is)
  if (Array.isArray(data.image_prompts)) {
    result.image_prompts = data.image_prompts;
  }

  // 4. Image style guidelines
  if (data.image_style_guidelines) {
    result.image_style_guidelines = data.image_style_guidelines;
  }

  // 5. Mapping suggestions
  if (data.mapping_suggestions) {
    result.mapping_suggestions = data.mapping_suggestions;
  }

  // 6. Image URLs (image1, image2, image3, ...)
  for (const key in data) {
    if (key.startsWith("image")) {
      result[key] = data[key];
    }
  }
}

return [
  {
    json: result
  }
];

// Get all incoming items
const items = $input.all();

// Safety check
if (items.length < 2) {
  throw new Error('Expected at least 2 items to merge');
}

// First item = original data
const baseData = items[0].json;

// Second item = generated output
const outputData = items[1].json;

// Merge them into one object
const merged = {
  ...baseData,
  generated_prompt: outputData.output
};

// Return a SINGLE item
return [
  {
    json: merged
  }
];

// Get all incoming items
const items = $input.all();

// Safety check
if (items.length < 3) {
  throw new Error('Expected at least 3 items');
}

// Item 0 = main post data
const baseData = items[0].json;

// Item 1 = generated image URL
const imageData = items[1].json;

// Item 2 = row metadata (contains row_number)
const rowData = items[2].json;

// Validate image URL
if (typeof imageData.image !== 'string' || imageData.image.trim() === '') {
  throw new Error('Second item does not contain a valid image URL');
}

// Validate row number
if (typeof rowData.row_number !== 'number') {
  throw new Error('Third item does not contain a valid row_number');
}

// Merge everything into ONE object
const merged = {
  ...baseData,
  post_url: imageData.image.trim(),
  row_number: rowData.row_number
};

// Return a SINGLE item
return [
  {
    json: merged
  }
];

const parsed = JSON.parse($json.output);

return [
  {
    selected_template: parsed.selected_template,
    image_prompts: parsed.image_prompts,
    image_style_guidelines: parsed.image_style_guidelines,
    mapping_suggestions: parsed.mapping_suggestions
  }
];

